// 1. Recibe la orden de tu página web
function doPost(e) {
  try {
    var requestData = JSON.parse(e.postData.contents);
    var tableName = requestData.tableName;
    var payload = requestData.payload;

    // 2. Credenciales ocultas (El cliente nunca las ve)
    var appId = "927a8f4f-34af-4e0e-8e19-4b304e84b1d2";
    var accessKey = "V2-SU8cK-s6uVM-8A6K8-gor0L-f0sTx-hSJ2F-FLhOW-dgmLx";
    var url = 'https://api.appsheet.com/api/v2/apps/' + appId + '/tables/' + tableName + '/Action';

    // 3. Habla con AppSheet (Sin límites ni bloqueos de CORS)
    var options = {
      'method': 'post',
      'contentType': 'application/json',
      'headers': { 'ApplicationAccessKey': accessKey },
      'payload': JSON.stringify(payload),
      'muteHttpExceptions': true
    };

    var response = UrlFetchApp.fetch(url, options);
    var responseCode = response.getResponseCode();
    var responseText = response.getContentText();

    if (responseCode !== 200) {
       throw new Error(responseText);
    }

    // 4. Le devuelve el OK a tu web
    return ContentService.createTextOutput(responseText)
      .setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({"error": error.message}))
      .setMimeType(ContentService.MimeType.JSON);
  }
}
